// Scoped to the single account named in the webhook body — no schedule/loop, no score>60
// gate: a human clicking "Create Jira Ticket" in the dashboard IS the escalation decision now.
const webhookData = $('Create Jira Ticket Webhook').first().json.body || $('Create Jira Ticket Webhook').first().json;
const targetName = (webhookData.account_name || '').toString().trim().toLowerCase();
if (!targetName) {
  throw new Error('Missing required field: account_name');
}

const rows = $input.all().map(i => i.json).filter(r => {
  const n = (r.account_name || r['account_name '] || '').toString().trim().toLowerCase();
  return n === targetName;
});
if (rows.length === 0) {
  throw new Error(`No RiskData row found for account_name "${webhookData.account_name}"`);
}

const byAccount = {};

for (const row of rows) {
  const name = (row.account_name || row['account_name '] || '').toString().trim();
  if (!name) continue;
  const score = parseFloat(row.financial_risk_score) || 0;
  const existing = byAccount[name];
  if (!existing || score > existing.financial_risk_score) {
    byAccount[name] = { ...row, account_name: name, financial_risk_score: score };
  }
}

function slugify(s) {
  return s.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

const qualifying = Object.values(byAccount)
  .map(a => ({
    account_name: a.account_name,
    account_label: `acct-${slugify(a.account_name)}`,
    severity_label: `sev-${(a.bug_severity || 'unknown').toLowerCase()}`,
    arr: a.arr,
    financial_risk_score: a.financial_risk_score,
    revenue_at_risk: a.revenue_at_risk,
    renewal_horizon_days: a.renewal_horizon_days,
    technical_domain: a.technical_domain,
    bug_summary: a.bug_summary,
    recommended_action: a.recommended_action
  }));

return qualifying.map(a => ({ json: a }));

const item = $input.first().json;
const steps = item.intermediateSteps || [];
const accountName = $('Collapse & Filter Accounts').first().json.account_name;

function tryParseJSON(x) {
  if (typeof x !== 'string') return x;
  try { return JSON.parse(x); } catch (e) { return null; }
}

let ticketKey = null;
let actionTaken = 'unknown';

for (const step of steps) {
  const toolName = ((step.action && (step.action.tool || step.action.toolName)) || '').toLowerCase();
  const obs = tryParseJSON(step.observation);
  if (!obs) continue;

  if (toolName.includes('create')) {
    const key = Array.isArray(obs) ? obs[0]?.key : obs.key;
    if (key) { ticketKey = key; actionTaken = 'created'; }
  } else if (toolName.includes('comment')) {
    if (actionTaken === 'unknown') actionTaken = 'commented';
  } else if (toolName.includes('search') && !ticketKey) {
    const issues = Array.isArray(obs) ? obs : (obs.issues || []);
    if (issues.length > 0 && issues[0].key) {
      ticketKey = issues[0].key;
      if (actionTaken === 'unknown') actionTaken = 'found_existing';
    }
  }
}

return [{
  json: {
    account_name: accountName,
    jira_ticket_key: ticketKey,
    action_taken: actionTaken,
    summary: item.output || item.text || ''
  }
}];
